import{_ as e,o as l,c as a,a3 as r}from"./chunks/framework.DACwFHq9.js";const x=JSON.parse('{"title":"通用与启动项","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/general-startup.md","filePath":"user-guide/settings/general-startup.md","lastUpdated":1778285333000}'),d={name:"user-guide/settings/general-startup.md"};function n(s,t,o,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="通用与启动项" tabindex="-1">通用与启动项 <a class="header-anchor" href="#通用与启动项" aria-label="Permalink to &quot;通用与启动项&quot;">​</a></h1><blockquote><p>通用设置控制 AIO Hub 的核心运行行为——从界面语言、窗口行为到网络代理和配置备份。启动项管理则让你控制各工具模块的自动启动策略。</p></blockquote><hr><h2 id="通用设置" tabindex="-1">通用设置 <a class="header-anchor" href="#通用设置" aria-label="Permalink to &quot;通用设置&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在设置左侧导航栏中点击「通用设置」选项卡。</li></ol><h3 id="配置管理" tabindex="-1">配置管理 <a class="header-anchor" href="#配置管理" aria-label="Permalink to &quot;配置管理&quot;">​</a></h3><p>设置面板顶部提供三个核心操作按钮：</p><table tabindex="0"><thead><tr><th style="text-align:left;">按钮</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>打开配置目录</strong></td><td style="text-align:left;">快速跳转到配置文件所在目录</td></tr><tr><td style="text-align:left;"><strong>导出配置</strong></td><td style="text-align:left;">将所有模块的配置打包为 ZIP 压缩包并保存到指定位置，导出的 ZIP 文件名会带上日期（如 <code>AIO-Tools-Backup-2025-10-01.zip</code>）</td></tr><tr><td style="text-align:left;"><strong>导入配置</strong></td><td style="text-align:left;">从 ZIP 文件恢复配置，可选择合并或覆盖模式</td></tr></tbody></table><h4 id="导入模式说明" tabindex="-1">导入模式说明 <a class="header-anchor" href="#导入模式说明" aria-label="Permalink to &quot;导入模式说明&quot;">​</a></h4><p>选择导入配置时，系统会弹出提示让你选择导入模式：</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">行为</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>合并导入</strong></td><td style="text-align:left;">保留现有配置，仅更新导入文件中存在的项。适合从旧版本迁移后要保留新增配置的情况</td></tr><tr><td style="text-align:left;"><strong>覆盖导入</strong></td><td style="text-align:left;">完全替换为导入文件中的配置。适合完全恢复或设置迁移</td></tr></tbody></table><blockquote><p>建议在重大版本更新前<strong>先导出备份配置</strong>，以防万一。</p></blockquote><hr><h3 id="窗口与托盘" tabindex="-1">窗口与托盘 <a class="header-anchor" href="#窗口与托盘" aria-label="Permalink to &quot;窗口与托盘&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">说明</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>显示托盘图标</strong></td><td style="text-align:left;">是否在系统托盘显示应用图标</td><td style="text-align:left;">关闭后，关闭到托盘功能不可用</td></tr><tr><td style="text-align:left;"><strong>关闭到托盘</strong></td><td style="text-align:left;">点击关闭按钮时最小化到托盘而非退出</td><td style="text-align:left;">需先启用「显示托盘图标」</td></tr><tr><td style="text-align:left;"><strong>窗口位置记忆</strong></td><td style="text-align:left;">点击「清除窗口状态」按钮，重置所有窗口的位置和大小记忆</td><td style="text-align:left;">下次打开窗口时恢复默认位置</td></tr><tr><td style="text-align:left;"><strong>自动调整窗口位置</strong></td><td style="text-align:left;">工具窗口移出屏幕时自动拉回可见区域</td><td style="text-align:left;">多屏切换时很有用</td></tr></tbody></table><hr><h3 id="主题设置" tabindex="-1">主题设置 <a class="header-anchor" href="#主题设置" aria-label="Permalink to &quot;主题设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">选项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>跟随系统</strong></td><td style="text-align:left;">自动跟随 Windows/macOS 系统主题切换</td></tr><tr><td style="text-align:left;"><strong>浅色</strong></td><td style="text-align:left;">固定使用浅色主题</td></tr><tr><td style="text-align:left;"><strong>深色</strong></td><td style="text-align:left;">固定使用深色主题</td></tr></tbody></table><blockquote><p>💡 想要更丰富的视觉定制？在「主题色配置」「主题壁纸外观」「CSS 样式覆盖」选项卡中可以配置主题色、壁纸、毛玻璃效果和窗口特效。详见 <a href="./appearance">外观与壁纸</a> 和 <a href="./custom-css">CSS 样式覆盖</a>。</p></blockquote><hr><h3 id="侧边栏模式" tabindex="-1">侧边栏模式 <a class="header-anchor" href="#侧边栏模式" aria-label="Permalink to &quot;侧边栏模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">效果</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认</strong></td><td style="text-align:left;">固定侧边栏，始终可见</td></tr><tr><td style="text-align:left;"><strong>抽屉</strong></td><td style="text-align:left;">侧边栏收起为一个图标按钮，点击展开</td></tr><tr><td style="text-align:left;"><strong>下拉菜单</strong></td><td style="text-align:left;">侧边栏变为顶部下拉菜单</td></tr></tbody></table><hr><h3 id="网络代理" tabindex="-1">网络代理 <a class="header-anchor" href="#网络代理" aria-label="Permalink to &quot;网络代理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">选项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>跟随系统</strong></td><td style="text-align:left;">使用操作系统的代理设置（推荐）</td></tr><tr><td style="text-align:left;"><strong>不使用代理</strong></td><td style="text-align:left;">所有网络请求直连</td></tr><tr><td style="text-align:left;"><strong>自定义</strong></td><td style="text-align:left;">手动输入代理 URL（如 <code>http://127.0.0.1:7890</code>）</td></tr></tbody></table><blockquote><p>对于需要访问境外 LLM API 的用户，可在「自定义」中输入你的代理地址。</p></blockquote><hr><h3 id="系统时区" tabindex="-1">系统时区 <a class="header-anchor" href="#系统时区" aria-label="Permalink to &quot;系统时区&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">选项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>跟随系统</strong></td><td style="text-align:left;">自动使用系统当前时区</td></tr><tr><td style="text-align:left;"><strong>手动选择</strong></td><td style="text-align:left;">从全球时区列表中选择（基于 <code>Intl.supportedValuesOf</code> 动态生成）</td></tr></tbody></table><p>影响日志时间戳、文件命名等与时间相关的显示。</p><hr><h3 id="下载设置" tabindex="-1">下载设置 <a class="header-anchor" href="#下载设置" aria-label="Permalink to &quot;下载设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认下载路径</strong></td><td style="text-align:left;">文件自动下载时的存放目录，留空使用系统默认下载目录</td></tr><tr><td style="text-align:left;"><strong>总是询问保存位置</strong></td><td style="text-align:left;">每次下载都弹出&quot;另存为&quot;对话框</td></tr><tr><td style="text-align:left;"><strong>显示下载完成通知</strong></td><td style="text-align:left;">下载完成后弹出系统通知</td></tr><tr><td style="text-align:left;"><strong>标题栏显示下载按钮</strong></td><td style="text-align:left;">在应用标题栏显示下载管理器入口按钮</td></tr></tbody></table><hr><h2 id="启动项管理" tabindex="-1">启动项管理 <a class="header-anchor" href="#启动项管理" aria-label="Permalink to &quot;启动项管理&quot;">​</a></h2><p>启动项管理位于通用设置面板中，是一个独立的模块，用于控制各工具模块在应用启动时的自动初始化行为。</p><h3 id="界面展示" tabindex="-1">界面展示 <a class="header-anchor" href="#界面展示" aria-label="Permalink to &quot;界面展示&quot;">​</a></h3><p>列表显示所有实现了自动启动能力的工具模块，每项包含：</p><table tabindex="0"><thead><tr><th style="text-align:left;">信息</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>名称</strong></td><td style="text-align:left;">工具模块名称</td></tr><tr><td style="text-align:left;"><strong>开关</strong></td><td style="text-align:left;">启用/禁用该启动项</td></tr><tr><td style="text-align:left;"><strong>上次启动结果</strong></td><td style="text-align:left;">成功 ✓ / 失败 ✗</td></tr><tr><td style="text-align:left;"><strong>耗时</strong></td><td style="text-align:left;">上次启动的耗时</td></tr><tr><td style="text-align:left;"><strong>错误信息</strong></td><td style="text-align:left;">启动失败时的错误详情</td></tr></tbody></table><h3 id="熔断保护机制" tabindex="-1">熔断保护机制 <a class="header-anchor" href="#熔断保护机制" aria-label="Permalink to &quot;熔断保护机制&quot;">​</a></h3><p>启动项管理内置<strong>熔断保护</strong>——如果某个工具连续多次启动失败，系统会自动禁用该启动项，防止反复失败影响应用整体启动速度。</p><ul><li>被熔断的工具会保留 <code>consecutiveFailures</code>（连续失败次数）和 <code>lastError</code>（最后错误信息）</li><li>你可以手动重新启用被熔断的启动项</li></ul><h3 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h3><ul><li>对于<strong>必需</strong>的工具（如资产管理），建议保持开启</li><li>对于<strong>偶尔使用</strong>的工具，可以关闭自动启动，使用时再手动打开</li><li>如果某个工具总是启动失败，检查其配置是否正确，或查看错误信息定位问题</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-修改通用设置后需要重启应用吗" tabindex="-1">Q：修改通用设置后需要重启应用吗？ <a class="header-anchor" href="#q-修改通用设置后需要重启应用吗" aria-label="Permalink to &quot;Q：修改通用设置后需要重启应用吗？&quot;">​</a></h3><p><strong>不需要。</strong> 大部分设置项修改后即时生效。少数设置（如侧边栏模式切换）可能需要重新加载界面。</p><h3 id="q-配置导出的-zip-文件包含哪些内容" tabindex="-1">Q：配置导出的 ZIP 文件包含哪些内容？ <a class="header-anchor" href="#q-配置导出的-zip-文件包含哪些内容" aria-label="Permalink to &quot;Q：配置导出的 ZIP 文件包含哪些内容？&quot;">​</a></h3><p>包含所有设置模块的配置文件（通用、外观、AI 服务、日志、资产管理等），但不包含用户数据文件（如聊天记录、用户资产文件等）。</p><h3 id="q-为什么「关闭到托盘」选项是灰色的" tabindex="-1">Q：为什么「关闭到托盘」选项是灰色的？ <a class="header-anchor" href="#q-为什么「关闭到托盘」选项是灰色的" aria-label="Permalink to &quot;Q：为什么「关闭到托盘」选项是灰色的？&quot;">​</a></h3><p>因为「显示托盘图标」处于关闭状态。先打开「显示托盘图标」，再配置关闭到托盘行为。</p><h3 id="q-启动项熔断后如何恢复" tabindex="-1">Q：启动项熔断后如何恢复？ <a class="header-anchor" href="#q-启动项熔断后如何恢复" aria-label="Permalink to &quot;Q：启动项熔断后如何恢复？&quot;">​</a></h3><p>在启动项列表中找到被禁用的工具，手动开启它的开关即可。建议先检查配置解决失败原因再启用。</p><hr><blockquote><p><strong>下一步</strong>：完成通用配置后，前往 <a href="./logs-assets">日志与资产管理</a> 了解如何管理系统日志和资产存储。</p></blockquote>',56)])])}const y=e(d,[["render",n]]);export{x as __pageData,y as default};
